def gen(rng, size):
    n1 = rng.randint(0, max(0, min(size, 60)))
    n2 = rng.randint(0, max(0, min(size, 60)))
    s1 = ''.join(rng.choice('ab') for _ in range(n1))
    s2 = ''.join(rng.choice('ab') for _ in range(n2))
    i = j = 0
    out = []
    while i < n1 or j < n2:
        if i < n1 and (j >= n2 or rng.random() < 0.5):
            out.append(s1[i]); i += 1
        else:
            out.append(s2[j]); j += 1
    return [s1, s2, ''.join(out)]

